   305→func (mg *Migrator) doMigration(ctx context.Context, m Migration) error {
   306→	ctx, span := tracer.Start(ctx, "Migrator.doMigration", trace.WithAttributes(
   307→		attribute.String("migration_id", m.Id()),
   308→	))
   309→	defer span.End()
   310→
   311→	logger := mg.Logger.FromContext(ctx)
   312→
   313→	sql := m.SQL(mg.Dialect)
   314→
   315→	record := MigrationLog{
   316→		MigrationID: m.Id(),
   317→		SQL:         sql,
   318→		Timestamp:   time.Now(),
   319→	}
   320→
   321→	err := mg.InTransaction(func(sess *xorm.Session) error {
   322→		// propagate context
   323→		sess = sess.Context(ctx)
   324→
   325→		err := mg.exec(ctx, m, sess)
   326→		// if we get an sqlite busy/locked error, sleep 100ms and try again
   327→		cnt := 0
   328→		for cnt < 3 && sqlite.IsBusyOrLocked(err) {
   329→			cnt++
   330→			logger.Debug("Database locked, sleeping then retrying", "error", err, "sql", sql)
   331→			span.AddEvent("Database locked, sleeping then retrying",
   332→				trace.WithAttributes(attribute.String("error", err.Error())),
   333→				trace.WithAttributes(attribute.String("sql", sql)),
   334→			)
   335→			time.Sleep(100 * time.Millisecond)
   336→			err = mg.exec(ctx, m, sess)
   337→		}
   338→
   339→		if err != nil {
   340→			logger.Error("Exec failed", "error", err, "sql", sql)
   341→			record.Error = err.Error()
   342→			if !m.SkipMigrationLog() {
   343→				if _, err := sess.Table(mg.tableName).Insert(&record); err != nil {
   344→					return err
   345→				}
   346→			}
   347→			return err
   348→		}
   349→		record.Success = true
   350→		if !m.SkipMigrationLog() {
   351→			_, err = sess.Table(mg.tableName).Insert(&record)
   352→		}
   353→		return err
   354→	})
   355→	if err != nil {
   356→		return tracing.Errorf(span, "migration failed (id = %s): %w", m.Id(), err)
   357→	}
   358→
   359→	span.SetStatus(codes.Ok, "")
   360→
   361→	return nil
   362→}
