   364→func (mg *Migrator) exec(ctx context.Context, m Migration, sess *xorm.Session) error {
   365→	logger := mg.Logger.FromContext(ctx)
   366→
   367→	start := time.Now()
   368→	logger.Info("Executing migration", "id", m.Id())
   369→
   370→	condition := m.GetCondition()
   371→	if condition != nil {
   372→		sql, args := condition.SQL(mg.Dialect)
   373→
   374→		if sql != "" {
   375→			logger.Debug("Executing migration condition SQL", "id", m.Id(), "sql", sql, "args", args)
   376→			results, err := sess.SQL(sql, args...).Query()
   377→			if err != nil {
   378→				logger.Error("Executing migration condition failed", "id", m.Id(), "error", err)
   379→				return err
   380→			}
   381→
   382→			if !condition.IsFulfilled(results) {
   383→				logger.Warn("Skipping migration: Already executed, but not recorded in migration log", "id", m.Id())
   384→				return nil
   385→			}
   386→		}
   387→	}
   388→
   389→	var err error
   390→	if codeMigration, ok := m.(CodeMigration); ok {
   391→		logger.Debug("Executing code migration", "id", m.Id())
   392→		err = codeMigration.Exec(sess, mg)
   393→	} else {
   394→		sql := m.SQL(mg.Dialect)
   395→		if strings.TrimSpace(sql) == "" {
   396→			logger.Debug("Skipping empty sql migration", "id", m.Id())
   397→		} else {
   398→			logger.Debug("Executing sql migration", "id", m.Id(), "sql", sql)
   399→			_, err = sess.Exec(sql)
   400→		}
   401→	}
   402→
   403→	if err != nil {
   404→		logger.Error("Executing migration failed", "id", m.Id(), "error", err, "duration", time.Since(start))
   405→		return err
   406→	}
   407→
   408→	logger.Info("Migration successfully executed", "id", m.Id(), "duration", time.Since(start))
   409→
   410→	return nil
   411→}
