   347→func (db *PostgresDialect) GetDBName(dsn string) (string, error) {
   348→	if strings.HasPrefix(dsn, "postgres://") || strings.HasPrefix(dsn, "postgresql://") {
   349→		parsedDSN, err := pq.ParseURL(dsn)
   350→		if err != nil {
   351→			return "", err
   352→		}
   353→		dsn = parsedDSN
   354→	}
   355→	re := regexp.MustCompile(`dbname=(\w+)`)
   356→	submatch := re.FindSubmatch([]byte(dsn))
   357→	if len(submatch) < 2 {
   358→		return "", fmt.Errorf("failed to get database name")
   359→	}
   360→	return string(submatch[1]), nil
   361→}
